#include <stdio.h>
#include <math.h>

long long ipow(long long base, int exp) {
    long long res = 1;
    while (exp--) res *= base;
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X;
        int c;
        scanf("%lld %d", &X, &c);
        long long original = X;
        long long ans = 1;
        for (long long p = 2; p * p <= X; ++p) {
            if (X % p == 0) {
                int e = 0;
                while (X % p == 0) {
                    X /= p;
                    ++e;
                }
                int r = e % c;
                if (r) ans *= ipow(p, r);
            }
        }
        if (X > 1) { // remaining prime factor with exponent 1
            int r = 1 % c;
            if (r) ans *= ipow(X, r);
        }
        // when c == 1, every exponent becomes 0, ans stays 1
        printf("%lld\n", ans);
    }
    return 0;
}

