code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static long ipow(long base, int exp) {
        long res = 1L;
        while (exp-- > 0) res *= base;
        return res;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            st = new StringTokenizer(br.readLine());
            long X = Long.parseLong(st.nextToken());
            int c = Integer.parseInt(st.nextToken());
            long ans = 1L;
            long n = X;
            for (long p = 2; p * p <= n; ++p) {
                if (n % p == 0) {
                    int e = 0;
                    while (n % p == 0) {
                        n /= p;
                        e++;
                    }
                    int r = e % c;
                    if (r != 0) ans *= ipow(p, r);
                }
            }
            if (n > 1) {
                int r = 1 % c;
                if (r != 0) ans *= ipow(n, r);
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys, math

def ipow(base, exp):
    res = 1
    while exp:
        res *= base
        exp -= 1
    return res

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it))
        c = int(next(it))
        n = X
        ans = 1
        p = 2
        while p * p <= n:
            if n % p == 0:
                e = 0
                while n % p == 0:
                    n //= p
                    e += 1
                r = e % c
                if r:
                    ans *= ipow(p, r)
            p += 1 if p == 2 else 2  # skip even numbers after 2
        if n > 1:
            r = 1 % c
            if r:
                ans *= ipow(n, r)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

