const T = Number(input[idx++]);
let results = [];
function ipow(base, exp) {
  let res = 1n;
  let b = BigInt(base);
  for (let i = 0; i < exp; ++i) res *= b;
  return res;
}
for (let t = 0; t < T; ++t) {
  let X = BigInt(input[idx++]);
  const c = Number(input[idx++]);
  let n = X;
  let ans = 1n;
  // trial division up to sqrt(n)
  for (let p = 2n; p * p <= n; ++p) {
    if (n % p === 0n) {
      let e = 0;
      while (n % p === 0n) {
        n /= p;
        ++e;
      }
      const r = e % c;
      if (r !== 0) ans *= ipow(p, r);
    }
    if (p === 2n) continue; // keep p=2 then next iteration will be 3
  }
  if (n > 1n) {
    const r = 1 % c;
    if (r !== 0) ans *= ipow(n, r);
  }
  results.push(ans.toString());
}
